"""
mkt-original layer — Acts chapters 22–24
Run: python3 scripts/zc-original-acts-22-24.py
Output: data/commentary/mkt-original/acts.json

Key decisions:
- Acts 22:2 Hebraidi dialektō — Aramaic, not classical Hebrew; the crowd's language shift
  produces silence; a strategic register-choice, not mere biographical detail
- Acts 22:9 contradiction with 9:7 (heard vs saw) is a perception-distinction not a factual
  error: 9:7 says they heard the sound (phōnē = sound) but saw no one; 22:9 says they heard
  not the voice (phōnē = voice/message) — Luke distinguishes the auditory experience levels
- Acts 22:14 ho dikaios ('the Righteous One') — a messianic title linking to Isa 53:11
  and Acts 3:14; 7:52; the title is Ananias's, not Paul's own invention
- Acts 23:1 syneidēsis ('conscience') — a Pauline technical term for moral self-awareness
  before God; its appearance here confirms Luke's representation of authentic Pauline idiom
- Acts 24:5 hairesis ('sect') — first application of this term to Christianity; Paul will
  reappropriate it (v.14) rather than deny it; a counter-labeling strategy
- Acts 24:17 the collection — Luke's only reference to Paul's famine-relief/collection project
  that dominates 2 Cor 8-9 and Rom 15:25-28; a historically significant corroboration
- Acts 24:22 Felix 'knowing the Way more accurately' — a historically plausible detail;
  Felix governed Judea for years and would have encountered the Jesus movement
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: add entries without overwriting existing ones
    # CHANGE? If schema changes, update here
    # VERIFY: after run, ch22/23/24 in mkt-original/acts.json have all verse keys
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "22": {
    "1": "<p><strong>apologia</strong> (<em>apologia</em>, 'defense'): the term carries both the everyday sense of self-defense before an accusation and the philosophical sense of Plato's <em>Apology</em> — Socrates defending his life and convictions before his accusers. Luke's use of <em>apologia</em> in Paul's speeches (22:1; 25:16; 26:2) frames Paul as an apostolic Socrates: a man of conviction defending truth before hostile audiences who cannot understand it. The appeal — 'brothers and fathers' (<em>andres adelphoi kai pateres</em>) — addresses both peer Israelites and the elder council members.</p>",

    "2": "<p><strong>Hebraidi dialektō</strong> ('in the Hebrew/Aramaic language'): first-century Palestinian 'Hebrew' virtually always means Aramaic — the spoken vernacular — rather than classical biblical Hebrew. The crowd's response (<em>mallon pareschon hēsychian</em>, 'they became even quieter') shows the strategic value of the language choice: Aramaic signals insider status, Jewish solidarity, and removes the suspicion that Paul has become culturally Hellenized. The register-shift is a calculated rhetorical move.</p>",

    "3": "<p><strong>anatetrammenos de en tē polei tautē</strong> ('raised in this very city'): Paul's three-stage identity — born in Tarsus, raised in Jerusalem, educated under Gamaliel — positions him as authentically Jewish despite Diaspora origin. <strong>para tous podas Gamaliēl</strong> ('at the feet of Gamaliel'): the standard posture for a rabbinic disciple seated before the teacher; Gamaliel I was one of the great sages of the period (the same Gamaliel as Acts 5:34). <em>Zeōtēs hyparchōn tou theou</em> ('being zealous for God'): Paul's pre-conversion zeal is his credibility — he was not an indifferent Jew who drifted toward Christianity but a committed one who was redirected.</p>",

    "4": "<p><strong>tēn hodon</strong> ('the Way'): the early self-designation of the Christian movement appears seven times in Acts (9:2; 19:9, 23; 22:4; 24:14, 22; 26:4). The metaphor of a <em>hodos</em> (road, way) carries OT resonance — the way of the LORD (Ps 25:4; Isa 40:3; Jer 6:16) — applied to the messianic community. <em>Mechri thanatou</em> ('unto death'): Paul does not minimize the consequences of his former persecution; the candor is strategically honest — he is not hiding his past but deploying it to establish the magnitude of his conversion.</p>",

    "5": "<p><strong>ho archiereus kai pan to presbyterion</strong> ('the high priest and the whole council of elders'): Paul calls his former authorities as character witnesses for his pre-conversion identity. The irony is structural: the very council that is now prosecuting him is the one that authorized him. His former letters from them are evidence of his zeal, not his criminality. The Damascus letters also attest to the Jerusalem council's sphere of authority over diaspora Jewish communities.</p>",

    "6": "<p><strong>phōs hikanon</strong> ('a considerable light'): Paul's Damascus Road account adds the detail 'about noon' (<em>peri mesēmbrian</em>) — midday, when the sun is at maximum brilliance. The light that exceeded the noonday sun signals a supranatural source. Paul's second-person account (22:6-16) differs slightly from Luke's third-person account (9:3-19) and Paul's Agrippa account (26:12-18) — the differences are consistent with oral re-telling variation, not contradiction.</p>",

    "7": "<p><strong>prosepeson te tō edaphei</strong> ('I fell to the ground'): the prostration response to divine presence is consistent throughout biblical theophanies (Ezek 1:28; Dan 8:17-18; Rev 1:17). The voice's question — <em>Saoul Saoul, ti me diōkeis</em> ('Saul, Saul, why do you persecute me?') — uses the Hebrew/Aramaic form of the name (double address = urgency and personal directness, cf. 'Abraham, Abraham' in Gen 22:11) and identifies Christ with the persecuted community: to persecute the church is to persecute Christ himself.</p>",

    "8": "<p><strong>Iēsous ho Nazōraios hon sy diōkeis</strong> ('Jesus the Nazarene, whom you are persecuting'): the identification preserves the geographic-historical particularity — Jesus of Nazareth, not an abstract divine principle. The Nazōraios designation consistently in Acts (2:22; 3:6; 4:10; 6:14; 22:8; 24:5; 26:9) anchors the risen Christ's identity to his historical humanity. The persecutor is re-oriented around a specific, named, historically located person who has proven stronger than death.</p>",

    "9": "<p><strong>to de phōs etheasanto tēn de phōnēn ouk ēkousan</strong> ('they saw the light but did not hear the voice'): the apparent contradiction with 9:7 ('hearing the voice but seeing no one') is a perception-distinction, not a factual error. Greek <em>phōnē</em> means both 'sound' (in 9:7 — they heard the auditory phenomenon) and 'voice/message' (in 22:9 — they did not comprehend the communicative content). The companions heard the sound of something but did not receive the word it conveyed; Paul alone received the speech.</p>",

    "10": "<p><strong>anastas poreuthēti eis Damaskon</strong> ('rise and go to Damascus'): the divine direction is specific, immediate, and geographic — not a mystical illumination but an itinerary. <em>Anakrinō</em> is not the word used here, but the structural pattern is consistent with OT prophetic commission: the encounter interrupts normal life, prostration and blinding follow, a specific destination is given. Paul's question — 'what shall I do, Lord?' — is the convert's first act of submitted discipleship.</p>",

    "11": "<p><strong>ōs de ouk eneblepon apo tēs doxēs tou phōtos ekeinou</strong> ('since I could not see because of the brilliance of that light'): Paul's temporary blindness — <em>apo tēs doxēs</em>, 'from the glory' — frames the experience as a theophany of divine glory comparable to Isaiah's (Isa 6:1-5) or Ezekiel's (Ezek 1:26-28). The glory of God's presence overwhelms human sight — not accidental but theologically significant: Paul cannot see the world in the old way; he must be led like a dependent child into the new.</p>",

    "12": "<p><strong>Ananias tis, anēr eulabes kata ton nomon, martyroumenos hypo pantōn tōn katoikountōn Ioudaiōn</strong> ('Ananias, a devout man according to the law, well-spoken of by all the Jews living there'): Paul's description of Ananias in the Jerusalem speech emphasizes his Jewish credentials — devout by the law, respected by the Jewish community — in contrast to Acts 9's simpler 'a disciple.' The emphasis serves Paul's apologetic: his commission came through a Torah-observant Jewish mediator, not a Hellenistic apostate.</p>",

    "13": "<p><strong>aneblepsas eis auton</strong> ('I received sight and looked at him'): the healing of sight enacts the Isaianic promise (Isa 42:7, 'to open eyes that are blind') applied to Paul himself before he will carry it to the Gentiles. The receiving of sight is the first sign of the new creation that has occurred in Paul; the physical restoration mirrors the spiritual re-orientation.</p>",

    "14": "<p><strong>ho dikaios</strong> ('the Righteous One'): Ananias's designation of Jesus echoes the messianic title used in Peter's Pentecost speech (3:14, 'the Holy and Righteous One') and Stephen's speech (7:52, 'the Righteous One'). The title draws from Isa 53:11 ('the righteous one, my servant, will justify many') and Zech 9:9 ('righteous and having salvation'). The Christological language Paul receives at his commission is consistent with the earliest apostolic tradition, grounding his apostleship in the community's confession.</p>",

    "15": "<p><strong>martys autō pros pantas anthrōpous</strong> ('his witness to all people'): the universal scope of Paul's witness mandate — <em>pros pantas anthrōpous</em> ('to all people') — is stated explicitly at his commissioning. The Gentile mission is not a later development or an accommodation; it is inscribed in Paul's original commission. The witness-language (<em>martys</em>) continues the Acts vocabulary of testimony grounded in personal encounter: Paul can witness because he has seen and heard.</p>",

    "16": "<p><strong>baptisai kai apolousai tas hamartias sou epikalesamenos to onoma autou</strong> ('be baptized and wash away your sins, calling on his name'): the baptismal formula connects three elements — the physical act (baptism), the spiritual effect (washing of sins), and the spiritual instrument (calling on his name). <em>Apolousai</em> (wash away) is the aorist middle of <em>apolōō</em> — in the middle voice, 'have yourself washed,' emphasizing the recipient's reception of an external act. The name-invocation links to Acts 2:38 and 22:10 ('what shall I do, Lord?').</p>",

    "17": "<p><strong>genesthai me en ekstasei</strong> ('I fell into a trance'): <em>ekstasis</em> is the technical term for visionary states throughout Luke-Acts (10:10; 11:5; 22:17) — a standing-outside-oneself in which normal sensory activity is suspended and divine communication occurs. Paul's temple vision — appearing here only in Paul's own account, not in Acts 9's narrative — establishes that he received direct revelation while in the very temple that represents Jewish covenantal identity.</p>",

    "18": "<p><strong>exelthe en tachei ex Ierousalēm, dioti ou paradexontai sou tēn martyrian peri emou</strong> ('leave Jerusalem quickly, because they will not accept your testimony about me'): the risen Christ's foreknowledge of Jerusalem's rejection anticipates the entire Acts narrative. <em>Martyria</em> (testimony) is the content Paul must offer; Jerusalem's rejection is foreseen and does not negate the mission — it redirects it toward the Gentiles (v.21).</p>",

    "19": "<p><strong>kyrte, autoi epistantai hoti egō ēmēn phylakizōn kai derōn kata tas synagōgas tous pisteuontas epi se</strong> ('Lord, they themselves know that I used to imprison and beat those who believed in you'): Paul's interjection — replying to the Lord's instruction to leave — reveals his pastoral logic: his past as persecutor makes him a credible witness to them. He reasons that those who knew his zeal would be compelled by his conversion. The Lord's response (v.21) overrides this pastoral reasoning with a broader divine purpose.</p>",

    "20": "<p><strong>kai hote exechynneto to haima Stephanou tou martyros sou</strong> ('and when the blood of Stephen your witness was shed'): <em>martys</em> applied to Stephen is the first use of the term in a sense approaching the later technical sense of 'martyr' — one who witnesses unto death. Paul's confession of his role (<em>autou kai symeurokōn kai phylassōn ta himatia tōn anairountōn auton</em>, 'consenting to his death and guarding the clothes of those killing him') is his most explicit admission of guilt, strategically placed in the account of his conversion.</p>",

    "21": "<p><strong>hoti egō eis ethna makran exapostelō se</strong> ('for I will send you far away to the Gentiles'): the divine commission is explicit, direct, and from the risen Lord in the temple — the most sacred Jewish space. The irony is total: the place of Jewish covenantal presence is where Paul receives his commission to the Gentiles. <em>Makran</em> ('far away') echoes Isa 57:19 ('peace to those far and near') and the Ephesians 2:13 vocabulary for Gentile distance from the covenant. The Gentile mission begins with a word spoken from the center of Israel's worship.</p>",

    "22": "<p><strong>tēn phōnēn autou heōs toutou tou logou</strong> ('his voice as far as this word'): 'Gentiles' is the trigger-word that breaks the crowd's silence. The audience that had settled to hear a Jewish defense (<em>Hebraidi dialektō</em>, v.2) erupts when the universal mission is announced. <em>Aire apo tēs gēs ton toiouton</em> ('take such a person from the earth'): the demand for Paul's death echoes the crowd's demand for Jesus (Luke 23:18, 'take him away!') — Luke's parallel is deliberate.</p>",

    "23": "<p><strong>rhiptountōn ta himatia kai koniorton ballontōn eis ton aera</strong> ('throwing off their cloaks and flinging dust into the air'): the gesture-complex — stripping outer garments and dust-throwing — is a theatrical expression of outrage, potentially involving ritual uncleaning gestures. The dust-throwing may echo the ancient custom of covering oneself with dust as mourning or protest. Luke's vivid detail suggests eyewitness or firsthand-source description of the scene.</p>",

    "24": "<p><strong>anazesthai auton mastixan</strong> ('to examine him by flogging'): the Roman interrogation technique of <em>flagellum</em> — the whip used for extracting information from non-citizens or slaves. Luke records the Roman tribune ordering what is technically an illegal procedure (v.25 will reveal the legal problem). The tribune acts out of imperial administrative logic — flog the troublemaker until he explains himself — without knowing or caring about Paul's legal status.</p>",

    "25": "<p><strong>ei anthrōpon Rhōmaion kai akatakriton exestin hymin mastizein</strong> ('is it legal for you to flog a man who is a Roman citizen and uncondemned?'): Paul's timing is exquisite — he speaks at the moment of maximum legal exposure for the tribune, not before (when it might be ignored) or after (when it would be too late). <em>Akatakriton</em> (uncondemned/without trial) is the legal term for summary punishment without due process. The citizen-claim precisely when the procedure is about to begin forces immediate pause.</p>",

    "26": "<p><strong>hora ti melleis poiein</strong> ('watch what you are about to do'): the centurion's warning to the commander shows the chain of accountability activated by the citizenship claim. The officer recognizes the legal risk before the commander does — he has seen enough of Roman law to know that flogging a citizen is prosecutable. The command structure responds correctly to the legal signal: escalate, don't proceed.</p>",

    "27": "<p><strong>Rhōmaios ei</strong> ('are you a Roman citizen?'): the tribune's question is the direct challenge; Paul's answer — <em>nai</em> ('yes') — is legally sufficient. Roman citizenship claims were taken seriously but were not verified on the spot; the legal penalty for false citizenship claims was severe enough that false claims were relatively rare. Paul's calm affirmation carries both legal weight and the spiritual composure of someone who knows his identity is secured at a deeper level than civic status.</p>",

    "28": "<p><strong>egō de kai gegennēmai</strong> ('but I was born to it'): Paul's birth-citizenship — hereditary rather than purchased — outranks the tribune's acquired citizenship. The social and legal hierarchy is unmistakable: birth-citizenship was the superior form. Paul does not elaborate on how his family acquired citizenship (possibly through service to Rome or through the Tarsian community's civic history), but the claim is specific and plausible given Tarsus's status as a free city.</p>",

    "29": "<p><strong>hoi mellontes auton anetazein ... phobēthēsan</strong> ('those about to examine him were afraid'): the fear is institutional — they have almost committed a crime against a Roman citizen. <em>Ho chiliarchos de ephobethe epignous hoti Rhōmaios estin kai hoti auton ēn dedekōs</em> ('the commander was also alarmed when he realized he was a Roman and that he had chained him'): chaining a Roman citizen without due process was itself illegal. The tribune's fear is now personal legal exposure, not merely administrative concern.</p>",

    "30": "<p><strong>bouleusē to asphales</strong> ('to find out the certain/exact truth'): <em>asphales</em> ('certain/secure') recurs throughout the Passion narrative section of Acts — the legal investigation seeks exactness that the riot's chaos denied. The tribune's decision to convene the Sanhedrin is his attempt to access the Jewish legal expertise that can tell him what Paul is actually accused of within Jewish law — the same kind of referral Pilate made to Herod (Luke 23:7).</p>"
  },

  "23": {
    "1": "<p><strong>syneidēsei agathē pepoliteumai tō theō</strong> ('I have lived my life before God with a clear conscience'): <em>syneidēsis</em> (conscience, moral self-awareness) is a Pauline technical term appearing 20 times in his letters (Rom 2:15; 9:1; 1 Cor 8:7; 10:25; 2 Cor 1:12; 1 Tim 1:5, 19; 3:9; 2 Tim 1:3, etc.). Its appearance here confirms Luke's authentic representation of Pauline idiom. <em>Pepoliteumai</em> (perfect — 'I have conducted myself as a citizen'): the civic vocabulary (<em>politeuō</em> = live as a citizen) frames the moral life as political participation, a Stoic-influenced usage Paul employs in Phil 1:27.</p>",

    "2": "<p><strong>Ananias ho archiereus</strong>: the high priest Ananias (not the same Ananias as Acts 5) served from approximately AD 47-58 and was notorious for violence and corruption (Josephus, <em>Ant.</em> 20.9.2; <em>Wars</em> 2.17.9). The order to strike Paul on the mouth — for claiming a clear conscience before even being questioned — is a violation of the Sanhedrin's own procedural norms. Paul's outrage in v.3 reflects a genuine legal-procedural grievance.</p>",

    "3": "<p><strong>tychesthai se ho theos, toiche kekoniamene</strong> ('God is going to strike you, you whitewashed wall!'): the 'whitewashed wall' imagery echoes Ezekiel 13:10-16, where God condemns the prophets who whitewash a flimsy wall — presenting an appearance of solidity over hollowness. Jesus uses similar imagery in Matt 23:27 ('whitewashed tombs'). Paul's outburst is prophetic denunciation, not mere insult — he is naming the gap between the high priest's judicial role and his actual behavior. The prediction ('God is going to strike you') will be partially enacted in Ananias's eventual assassination (AD 66).</p>",

    "4": "<p>The bystanders' rebuke — <em>ton archiera tou theou loidoreis</em> ('are you insulting God's high priest?') — highlights the gap between office and conduct. The office deserves honor; the conduct Paul observed deserved rebuke. Paul's reply (v.5) is often read as sarcastic ('I did not know he was high priest' — when it might have been obvious from his position) or as genuine disorientation after the previous day's chaos, or as a reference to Ananias's irregular tenure.</p>",

    "5": "<p><strong>ouk ēdein, adelphoi, hoti estin archiereus</strong> ('I did not know, brothers, that he was the high priest'): Paul's citation of Exod 22:28 — 'do not speak evil of a ruler of your people' — shows his knowledge of Torah and his willingness to submit to its authority even when applying it against himself. Whether the statement is ironic or straightforward, Paul handles the correction by appealing to Scripture — modeling the behavior he expects of the Sanhedrin.</p>",

    "6": "<p><strong>Farisaios ... huios Farisaiōn</strong> ('a Pharisee, the son of Pharisees'): Paul's declaration of Pharisaic identity before the Sanhedrin is not opportunistic but historically accurate (Phil 3:5 — 'a Pharisee'). The immediate exploitation of the Pharisee-Sadducee division on resurrection is a strategic move to divide the council — but it is not dishonest: Paul's hope of resurrection is the genuine center of his message. <em>Elpidos kai anastaseōs nekrōn egō krinomai</em> ('it is concerning the hope and resurrection of the dead that I am being judged') is the accurate theological summary of the issue.</p>",

    "7": "<p><strong>schisma tou plēthous</strong> ('a split of the assembly'): the council's division is Luke's demonstration that the resurrection — the central Christian claim — was a live, contested, and divisive issue within Judaism itself. The Sadducees and Pharisees did not agree on it. Paul's strategy works because it is theologically accurate: he stands in the Pharisaic tradition of resurrection hope that the Sadducees rejected, and the Pharisees know it.</p>",

    "8": "<p><strong>Saddoukaioi men gar legousin mē einai anastasin mēte angelon mēte pneuma</strong> ('the Sadducees say there is no resurrection, neither angel nor spirit'): Luke's parenthetical theological note on the Sadducees' position is confirmed by Josephus (<em>Ant.</em> 18.1.4) and the NT Gospels (Mark 12:18). The triple denial — no resurrection, no angels, no spirits — seems to have been a Sadducean theological position that distinguished them from Pharisees who affirmed all three. The Pharisees' vigorous defense of Paul in v.9 reflects genuine theological solidarity, not political maneuvering.</p>",

    "9": "<p><strong>ei de pneuma elalēsen autō e angelos</strong> ('what if a spirit or an angel has spoken to him?'): the Pharisees' open question — perhaps the risen Christ spoke to Paul through a heavenly messenger — is the most generous theological interpretation of his Damascus experience that a non-believing Pharisee could offer. They cannot deny resurrection as a category; they must at least consider that Paul's encounter fits within their own worldview. Luke records this concession without suggesting the Pharisees became Christians; they are defending their tradition against the Sadducees more than defending Paul.</p>",

    "10": "<p><strong>mē diaspassthē ho Paulos hyp' autōn</strong> ('Paul should be torn apart by them'): the physical danger — <em>diaspaō</em> (tear to pieces) — reflects the intensity of the Sanhedrin dispute. The tribune's intervention (rescuing Paul again) continues the pattern of Roman authority protecting Paul from Jewish mob violence. The paradox of Roman imperial machinery repeatedly saving the apostle to the Gentiles is Luke's ironic commentary on God's providential use of secular power.</p>",

    "11": "<p><strong>tharsei</strong> ('take courage'): the Lord's nocturnal appearance (<em>ephistas autō ho kyrios eipen</em>, 'standing by him the Lord said') uses the same vocabulary as the divine commissioning appearances throughout Acts (18:9-10; 27:23-24). <em>Dei se kai eis Rhōmēn martyrēsai</em> ('you must testify about me in Rome also'): <em>dei</em> is divine necessity — the same compulsion that drove Jesus's entire ministry. The mission to Rome is not contingent on favorable circumstances but guaranteed by divine mandate. Paul's imprisonment is within this mandate, not contrary to it.</p>",

    "12": "<p><strong>anathema</strong> ('a solemn oath/curse'): the conspirators bound themselves with an oath (<em>anathematisantes heautous</em>) — the strongest Jewish oath form, placing oneself under divine curse if the vow is broken. The vow not to eat or drink until Paul is dead is a life-threatening commitment. Luke records the plot in detail (vv.12-15) to show both the seriousness of the opposition and the providential chain by which Paul escapes: a nephew, a chance encounter, a Roman military bureaucracy.</p>",

    "13": "<p>The number 'more than forty' (<em>pleiōn tesserakonta</em>) who made the assassination oath is specific enough to suggest Luke had access to detailed information about the conspiracy — perhaps from Paul's own later account of the plot, or from community members who knew the story. The precision of the number throughout the Acts travel accounts and conflict reports is characteristic of Luke's historical sourcing.</p>",

    "14": "<p><strong>anathemati anethematisamen heautous</strong> ('we have bound ourselves with a solemn curse'): the intensive cognate construction (<em>anathema</em> + <em>anathematizō</em>) is the Greek equivalent of a Hebrew absolute infinitive construction — the most emphatic form of the verb, signaling the binding's absolute seriousness. The conspirators go to the chief priests and elders — the same body that had tried to suppress the apostles (chs. 4-5) — now as allies in another attempt to eliminate the movement's key leader.</p>",

    "15": "<p><strong>hōs mellontas diaginōskein akribesteron ta peri autou</strong> ('as if you were going to examine his case more carefully'): the Sanhedrin is asked to use the pretext of judicial inquiry to create an ambush opportunity. The conspiracy requires the complicity of the official judicial body — they must request a retrial with legitimate-sounding reasons. Luke records the full mechanics to expose the gap between the council's judicial role and its actual murderous intent.</p>",

    "16": "<p><strong>ho huios tēs adelphēs Paulou</strong> ('the son of Paul's sister'): Paul's nephew — the only reference to Paul's extended family in the entire NT. The detail is specific and unverifiable but consistent with Luke's biographical sourcing. The nephew's access to both the conspiracy's information and to the barracks where Paul was held suggests a family with sufficient social standing to move between Jewish and Roman circles. Luke does not explain how the nephew learned of the plot; he narrates the providence without editorializing.</p>",

    "17": "<p><strong>eis ton chiliarchon</strong> ('to the commander'): Paul's access to the tribune through the military chain of command — calling a centurion, requesting the centurion escort the young man, the centurion complying — shows Paul operating with considerable personal authority even while a prisoner. The Roman military hierarchy is navigable and responsive; Paul uses it effectively. The apostle's imprisonment does not remove his capacity for strategic agency.</p>",

    "18": "<p>The centurion's speech to the commander — <em>ho desmios Paulos prosekalesmenos me</em> ('the prisoner Paul called me') — is a model of institutional communication: factual, deferential, complete. Luke's representation of Roman military communication throughout Acts 22-28 is consistently credible; his detailed knowledge of Roman procedures supports the 'we' narrator's firsthand experience of the journey.</p>",

    "19": "<p><strong>epilabomenos de tēs cheiros autou ho chiliarchos kai anachorēsas kat' idian</strong> ('the commander took the young man by the hand and drew him aside privately'): the intimate gesture — taking by the hand — and the private setting signal the commander's recognition that this information requires careful handling. He does not dismiss or minimize the nephew's approach but gives it full formal attention. The care with which Roman authority handles Paul throughout these chapters reflects Luke's portrait of Roman justice as (imperfectly) responsive to legitimate claims.</p>",

    "20": "<p>The young man's report is specific, verifiable, and delivered with appropriate urgency. <em>Sunethento tou erōtēsai se</em> ('they have agreed to ask you'): he identifies the conspiracy as a coordinated plan (<em>syntithemai</em> = agree together), not a spontaneous threat. Luke's repetition of the conspiracy details (vv.12-15, 20-21) through the nephew's report to the tribune serves both narrative and documentary functions — confirming the details while showing how information moved in apostolic-era Jerusalem.</p>",

    "21": "<p><strong>anathemati anethematisan heautous mē phagein mēde piein heōs ou anelōsin auton</strong> ('they have bound themselves with a solemn curse not to eat or drink until they have killed him'): the nephew's precise report — 'more than forty of them,' the oath, the plan to ambush — carries the urgency of firsthand intelligence. His instruction — 'don't give in to them' (<em>mē peisthai autois</em>) — is direct and actionable. The tribune acts immediately on the information, without questioning its source.</p>",

    "22": "<p><strong>ekeleuse mēdeni eklaein hoti tauta enephanisas pros me</strong> ('he ordered him to tell no one that he had reported this to him'): the tribune's caution about secrecy — protecting the source — reflects competent intelligence handling. The nephew's anonymity is maintained in Luke's account too; he is never named. The secrecy protects both the young man and the effectiveness of the tribune's counter-plan.</p>",

    "23": "<p><strong>stratiotai diakosioi, hippeis hebdomekonta, dexiolabous diakosioi pentēkonta</strong> ('200 soldiers, 70 cavalry, 200 spearmen'): the escort of 470 soldiers for one prisoner reflects either the seriousness with which the Roman tribune took the assassination threat or Luke's access to official records (the numbers are suspiciously precise). <em>Dexiolaboi</em> (spearmen/right-hand men) is a hapax — a technical term for a specialized auxiliary unit; its specificity supports Luke's access to military records.</p>",

    "24": "<p><strong>ktemē te parastēsai</strong> ('provide animals/horses for Paul to ride'): Paul's transportation by horse elevates him above the walking prisoner of the typical convoy. The order to bring him 'safely' (<em>diasōsōsin</em>) to Felix is the commander's legal obligation — having identified him as a Roman citizen, Lysias is responsible for his safety until he is properly delivered to the provincial governor. The transfer to Felix initiates the extended Caesarean imprisonment of chs. 24-26.</p>",

    "25": "<p><strong>grapsas epistolēn echousan ton typon touton</strong> ('having written a letter with this form'): Luke records the letter's content as a diplomatic document — formal opening (<em>Klaudios Lysias tō kratistō hēgemoni Phēliki chairein</em>, v.26), narrative body, and legal conclusion. Whether Luke had access to the actual letter or reconstructed it from Paul's knowledge of its contents, the document's form is consistent with Roman official correspondence.</p>",

    "26": "<p><strong>Klaudios Lysias tō kratistō hēgemoni Phēliki chairein</strong> ('Claudius Lysias to His Excellency Governor Felix: Greetings'): the formal epistolary opening identifies the tribune by name (Claudius Lysias — the only place his name is given in Acts), establishes his rank, addresses the governor with the appropriate title (<em>kratistos</em> = 'most excellent', the standard address for equestrian-rank officials), and uses the standard Hellenistic greeting (<em>chairein</em>). The letter's form is impeccable.</p>",

    "27": "<p><strong>sylalemphthenta hypo tōn Ioudaiōn kai mellonta anairēisthai hyp' autōn</strong>: Lysias's version of the rescue slightly reorders the events — he presents himself as having rescued Paul knowing he was a Roman citizen, whereas Acts 22 shows he learned Paul's citizenship only after ordering the flogging. The self-serving revision in an official report is realistic — bureaucrats protect themselves in written records — and Luke records both versions without harmonizing them, allowing the discrepancy to speak for itself.</p>",

    "28": "<p><strong>eis to synedrion autōn</strong> ('to their Sanhedrin'): Lysias's correct identification of the dispute as internal Jewish-law matter (<em>peri zētēmatōn tou nomou autōn</em>, 'concerning disputes about their own law') anticipates Felix's, Festus's, and Agrippa's similar conclusions. The Roman judicial tradition repeatedly recognizes that Paul's case involves Jewish religious law, not Roman criminal law — a conclusion that should result in release, but political calculation prevents.</p>",

    "29": "<p><strong>mēden axion thanatou ē desmōn echonta enklēma</strong> ('having no charge deserving death or imprisonment'): Lysias's legal judgment — that Paul is innocent of any capital or custodial offense — is the third of the innocence declarations that structure Acts 22-26 (alongside Festus in 25:25 and Agrippa in 26:31-32). The pattern mirrors the triple innocence declarations of the Passion (Pilate in Luke 23:4, 14, 22). Paul's imprisonment is politically managed injustice, as Jesus's crucifixion was.</p>",

    "30": "<p><strong>pempsas pros se kai tois katēgorois parēngeila</strong> ('sending him to you and ordering his accusers'): the formal transfer — sending both the prisoner and his accusers to Felix — is the correct procedure for trans-jurisdictional cases in the Roman system. Lysias performs the transfer properly even if his letter's self-presentation is slightly distorted. The case now enters the provincial governor's jurisdiction, where it will remain for two years (24:27).</p>",

    "31": "<p>The troop movement — taking Paul by night to Antipatris (about 35 miles from Jerusalem, at the edge of the coastal plain) — is geographically specific and militarily logical. At Antipatris, the infantry could return to Jerusalem (the immediate assassination threat was past once they left the Judean hills) and the cavalry alone could escort Paul the remaining 25 miles to Caesarea. Luke's knowledge of the route and the troop movement suggests either a traveler's memory or access to military records.</p>",

    "32": "<p><strong>tous hippeis apelthein syn autō</strong> ('leaving the cavalry to continue with him'): the military logic is sound — once past the danger zone, fewer troops are needed. The narrative's attention to the troop-reduction detail is one of many specifics in Acts 23-27 that suggest Luke was physically present on part of the journey and remembered the operational details.</p>",

    "33": "<p><strong>aperidokan kai ton Paulon autō parestēsan</strong> ('they delivered the letter and presented Paul to him'): the formal handover — letter first, then prisoner — follows Roman administrative procedure. The governor's preliminary inquiry (v.34) about province of origin establishes personal jurisdiction; Felix confirms his authority over Cilicia and proceeds to hear the case in his official capacity.</p>",

    "34": "<p><strong>apo poias eparchias estin</strong> ('what province he was from'): the question establishes whether Felix has jurisdiction or whether the case belongs to the governor of Paul's home province. Cilicia was at this period governed from Syria, but Felix apparently accepted jurisdiction without difficulty, perhaps because Paul had been arrested in Judea and the charges arose there.</p>",

    "35": "<p><strong>en tō praitōriō tou Hērōdou phylassesthai auton</strong> ('to be kept under guard in Herod's praetorium'): the praetorium at Caesarea — built by Herod the Great as his coastal palace — had become the Roman governor's official residence and administrative center. Paul's custody in the praetorium is not punitive but administrative — he is a formal prisoner awaiting trial, with the legal protections due his status. Phil 1:13 ('throughout the praetorium') may reflect Paul's knowledge of this administrative headquarters from his Caesarean imprisonment.</p>"
  },

  "24": {
    "1": "<p><strong>meta pente hēmeras katebē ho archiereus Ananias</strong> ('after five days the high priest Ananias went down'): the high priest himself travels from Jerusalem to Caesarea — an unusual step that signals the seriousness of the case to the Jerusalem leadership. <em>Rhētoros Tertullou tinos</em> ('a certain orator named Tertullus'): Tertullus is a professional advocate trained in Latin forensic rhetoric — the first explicit appearance of a professional lawyer in Acts. His name is Roman; he may be a Romanized Jew or a Gentile hired for his rhetorical expertise.</p>",

    "2": "<p><strong>pollēs eirēnēs tynchanontes</strong> ('we enjoy much peace'): Tertullus's opening is a masterpiece of Roman forensic flattery — the <em>captatio benevolentiae</em> required by rhetorical convention. The claim of peace and prosperity under Felix is historically ironic; Felix's tenure was marked by significant unrest and brutal suppression of various movements (Josephus, <em>Ant.</em> 20.7-8; <em>Wars</em> 2.13). The flattery is formulaic rather than factual, which Tertullus knows and Felix knows; the game of rhetoric proceeds anyway.</p>",

    "3": "<p><strong>pantē te kai pantachou apodechometha, kratiste Phēlix, meta pasēs eucharistias</strong> ('everywhere and in every way we acknowledge this with profound gratitude, most excellent Felix'): the accumulated superlatives — everywhere, every way, most excellent, profound gratitude — pile up to exaggerate the compliment. The very density of the flattery signals its conventional character. Roman forensic oratory expected such openings; the court expected them; Felix would have measured the speech by its argumentative quality rather than its compliments.</p>",

    "4": "<p><strong>kleptō se epi pleion</strong> ('I do not want to detain you further'): the <em>brevitas</em> topos — claiming brevity before a long speech — was a standard rhetorical device. Tertullus's actual speech is relatively brief; his promise of brevity is kept more than most orators who invoke it. <em>Tē sē epieikeia</em> ('your indulgence/clemency'): appealing to the judge's character-virtue (<em>epieikeia</em> = fairness, reasonableness) as the ground for a favorable hearing is conventional advocacy.</p>",

    "5": "<p><strong>loimos</strong> ('a pest/plague'): a stock insult in ancient rhetoric for political troublemakers and social agitators. <em>Prōtostatēs</em> ('ringleader/chief man'): a military term for the man in the front rank, applied here as 'leader' of the sect. <em>Hairesis</em> ('sect'): the first application of this term to the Nazarenes in Acts. <em>Hairesis</em> in Paul's usage (1 Cor 11:19; Gal 5:20) is pejorative — 'faction, divisive party'; Tertullus uses it to characterize Christianity as a schismatic movement within Judaism rather than a legitimate tradition.</p>",

    "6": "<p><strong>ton hieron epeiresen bebēlōsai</strong> ('he tried to desecrate the temple'): the charge is the most serious — temple desecration was a capital offense under Jewish law (Josephus confirms Gentiles faced execution for entering the inner courts, <em>Wars</em> 6.2.4). The actual charge (21:28) was that Paul brought Trophimus the Ephesian into the temple — not proven, and now the accusers have dropped to the vaguer 'tried to desecrate.' The case is deteriorating legally from an alleged specific act to an attempted offense.</p>",

    "7": "<p>The verse (omitted in some manuscripts; included in the textus receptus) accuses Lysias of forcible intervention in Jewish jurisdiction. Its authenticity is uncertain; it was possibly added to explain the transition in v.8 from the temple arrest to the examination of Paul. The Western text's expansion of Acts at this point is a known textual tendency; most modern translations bracket or omit v.7.</p>",

    "8": "<p><strong>para hou dynēsē autos anakrinas peri pantōn toutōn epignōnai</strong> ('from whom you will be able, by examining him yourself, to find out the truth about all these charges'): Tertullus refers the decisive evidence to Paul himself — an unusual rhetorical strategy. He assumes Felix's examination will confirm the charges. The confidence reflects either genuine assurance in the case or a rhetorical bluff relying on Felix's unfamiliarity with the details.</p>",

    "9": "<p><strong>synepethento de kai hoi Ioudaioi phaskontes tauta houtōs echein</strong> ('the Jews also joined in the accusation, asserting that these things were so'): the congregation of accusers (<em>synepetithento</em>, literally 'attacked together') is a collective witness endorsement. In Roman law, multiple witnesses were important; the concurrence of the high priest, elders, and the crowd provides what appears to be overwhelming testimony. Paul's response must counter all of it.</p>",

    "10": "<p><strong>ek pollōn etōn onta se kritēn tō ethnei toutō epistamenos</strong> ('knowing that you have been a judge over this nation for many years'): Paul's <em>captatio benevolentiae</em> is noticeably shorter and more measured than Tertullus's — he compliments Felix's experience rather than his beneficence. Experience as a judge is a neutral compliment; it appeals to Felix's judicial competence rather than his generosity. Paul's shorter opener models the compressed advocacy style he will employ throughout.</p>",

    "11": "<p><strong>ou pleiōn eisin moi hēmerai dōdeka</strong> ('it has not been more than twelve days'): Paul introduces temporal specificity as a legal argument — the brevity of his Jerusalem visit is incompatible with the charge of organizing widespread agitation. Twelve days is not enough time to build the kind of movement the accusers describe. The chronological argument is one of three positive defenses Paul offers (the others being eyewitness verification, v.12, and the absence of proper witnesses, v.19).</p>",

    "12": "<p><strong>oute en tō hierō heuron me pros tina dialegomonon</strong> ('they did not find me arguing with anyone at the temple'): Paul's denial is categorical and specific — not arguing in the temple, not stirring up crowds in the synagogues, not creating disturbances anywhere in the city. The tripartite denial directly addresses Tertullus's three-part charge (troublemaker, ringleader of a sect, temple desecrator). The legal form of the defense mirrors the form of the accusation.</p>",

    "13": "<p><strong>oude parastēsai dynantai soi peri hōn nyn katēgorousin mou</strong> ('nor can they prove to you the charges they are now bringing against me'): the burden-of-proof argument — <em>paristēmi</em> (prove, demonstrate) is a legal term — places the evidentiary burden where Roman law placed it: on the accusers. Paul does not merely deny; he challenges the accusers to produce verifiable evidence. The challenge will go unanswered (v.19 — the real witnesses are not present).</p>",

    "14": "<p><strong>kata tēn hodon ēn legousin hairesin</strong> ('according to the Way which they call a sect'): Paul's reappropriation of Tertullus's <em>hairesis</em> (v.5) is a rhetorical counter. He accepts the label ('which they call a sect') while denying its pejorative force — the Way is not a destructive faction but the fulfillment of the ancestral faith. <em>Latreuon tō patrōō theō</em> ('worshipping the ancestral God') and <em>pisteuōn pasin tois kata ton nomon kai tois en tois prophētais gegrammēnois</em> ('believing all things in the Law and the Prophets') — Christianity is not apostasy from Israel's Scripture but its fulfillment.</p>",

    "15": "<p><strong>elpida echōn eis ton theon ēn kai autoi houtoi prosdechontai</strong> ('having a hope toward God which these men themselves also hold'): Paul's counter-framing finds common ground with the Pharisees in the Sanhedrin delegation — the hope of resurrection. <em>Anastasin mellein esesthai dikaiōn te kai adikōn</em> ('that there will be a resurrection of both the righteous and the wicked'): the universal resurrection is from Dan 12:2, the most explicit OT text for bodily resurrection of both groups. Paul's hope is within Israel's canonical expectation.</p>",

    "16": "<p><strong>aproskopon syneidēsin echein pros ton theon kai tous anthrōpous dia pantos</strong> ('to have a clear conscience toward God and man always'): <em>aproskopos</em> (not stumbling, causing no offense) + <em>syneidēsis</em> (conscience) — the same vocabulary cluster as 23:1. Paul's consistent use of <em>syneidēsis</em> before both Jewish (23:1) and Roman (24:16) audiences shows the term's cross-cultural currency. The phrase acknowledges a dual accountability — to God and to human community — without subordinating either.</p>",

    "17": "<p><strong>dia etōn pleionōn... poiēsōn eis to ethnos mou eleēmosynas kai prosphoras</strong> ('after several years... bringing alms to my nation and offerings'): Luke's only reference to Paul's collection from Gentile churches for Jerusalem's poor (cf. 2 Cor 8-9; Rom 15:25-28; 1 Cor 16:1-3). The collection was Paul's major organizational project of his third missionary journey — evidence of the Gentile churches' solidarity with the Jerusalem community. Paul presents this not as a doctrinal claim but as verifiable action: he came for charity and worship, not agitation.</p>",

    "18": "<p><strong>hēgnismenon en tō hierō</strong> ('having completed the purification rite in the temple'): Paul's temple presence was in the context of fulfilled purification vows — precisely the most Jewish possible activity, not desecration. He was in the state of ritual purity (<em>hagnismenon</em>), performing the socially approved act of completing a Nazirite-related vow, when the accusation arose. The charge of desecration collapses against the actual circumstances of his temple visit.</p>",

    "19": "<p><strong>hous edei epi sou pareinai kai katēgorein</strong> ('who ought to be present before you and make an accusation'): the absent-witnesses argument is Paul's strongest legal point. Roman law required accusers to appear in person (cf. the Lysias letter, 23:30; Trajan's rescript to Pliny, <em>Ep.</em> 10.97). The Asian Jews who originally made the charge are not present; the Sanhedrin is representing a case it did not witness. This procedural deficiency should, by Roman law, end the case.</p>",

    "20": "<p><strong>e autoi houtoi eipatōsan ti heuron adikēma</strong> ('or else let these men here state what crime they found in me'): Paul invites the present accusers — those who were at the Sanhedrin hearing — to state their case directly. The only specific charge they can offer is the theological one: resurrection (v.21). Everything else is allegation without evidence. Paul's advocacy is tight and specific; he is forcing the accusers to narrow to the actual substantive disagreement.</p>",

    "21": "<p><strong>peri anastaseōs nekrōn egō krinomai sēmeron eph' hymōn</strong> ('it is concerning the resurrection of the dead that I am being judged today before you'): Paul's self-summary of the issue cuts through all the political and procedural noise to the theological core. The resurrection is the real question; everything else is obscuring it. His use of the first person singular (<em>egō krinomai</em>) — 'I am being judged' — owns the situation without apology. The statement is both legally accurate and theologically definitive.</p>",

    "22": "<p><strong>akribEsteron eidōs ta peri tēs hodou</strong> ('knowing the Way more accurately'): Felix's knowledge of the Way — whether through his Jewish wife Drusilla, through administrative experience in Judea, or through other sources — is historically plausible. <em>Anebaleato autous</em> ('he adjourned the proceedings'): the verb signals a formal procedural postponement, not dismissal. Felix neither convicts nor acquits; his deferral is a judicial non-decision driven by political calculation.</p>",

    "23": "<p><strong>echein te anesin</strong> ('to have some freedom/relief'): Paul's custody is <em>custodia libera</em> (free custody) — not imprisonment in a cell but house arrest with supervision. <em>Kai mēdena kōlyein tōn idiōn autou hypēretein autō</em> ('no one to prevent his own people from serving him'): the apostolic community can access Paul, bring resources, and maintain relationship. This explains how Paul maintained his ministry connections during the Caesarean imprisonment and presumably wrote or dictated letters during this period (possibly including Philippians or Philemon).</p>",

    "24": "<p><strong>Drusilla, gynaiki ousē Ioudaia</strong> ('with his wife Drusilla, who was Jewish'): Drusilla was the youngest daughter of Herod Agrippa I (who died in Acts 12:23) and the sister of Agrippa II (who will appear in chs. 25-26). She had left her previous husband Azizus of Emesa to marry Felix — a marriage that violated both Jewish law (marriage to an uncircumcised Gentile) and social convention. Her Jewish identity made her particularly well-placed to understand Paul's arguments. <em>Pisteos tēs eis Christon Iēsoun</em> ('faith in Christ Jesus'): Paul speaks directly to the theological core even before the most powerful audience he has had.</p>",

    "25": "<p><strong>peri dikaiosynēs kai enkrateias kai tou krimatos tou mellontos</strong> ('about righteousness, self-control, and the judgment to come'): the three themes are an apostolic précis of the ethical and eschatological claims of the gospel. <em>Dikaiosynē</em> (righteousness) before a corrupt governor; <em>enkrateia</em> (self-control) to a man who had induced another man's wife to leave her husband; <em>krima mellon</em> (the coming judgment) to a man who had misused his judicial power. Paul's message is precisely calibrated to Felix's moral situation. <em>Emphobos genomenos</em> ('becoming afraid') — Felix's fear is the recognition of personal moral exposure.</p>",

    "26": "<p><strong>chrēmata dothēsetai autō hypo tou Paulou</strong> ('money would be given to him by Paul'): Felix's hope for a bribe — <em>chrēmata</em> (money) — shows the corruption that Luke has been implying. The frequency of Felix's conversations with Paul (<em>pyknōteron metepempto auton kai hōmilei autō</em>, 'he sent for him frequently and conversed with him') reveals mixed motives: some genuine interest (perhaps through Drusilla) and mercenary calculation. Paul's readiness to speak to Felix repeatedly despite the bribe-hope is his sustained witness to a powerful, sinful audience.</p>",

    "27": "<p><strong>dietias de plērōtheis ... katēleipen ton Paulon dedemenon</strong> ('after two years had passed... he left Paul imprisoned'): Felix's replacement by Porcius Festus (c. AD 59) ends the Caesarean episode. Felix's final act — leaving Paul imprisoned <em>charin katathesthai tois Ioudaiois</em> ('to show favor to the Jews') — is a straightforwardly political decision: sacrifice a prisoner's legal rights to maintain political relationships. The two-year imprisonment is the time between Paul's arrival in Caesarea (24:27) and his eventual appeal to Caesar, the event that will send him to Rome and fulfill the divine mandate of 23:11.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'acts')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', 'acts', existing)
    for ch in ['22', '23', '24']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
